#include "./main.h"

#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <omp.h>

#include "./../util/graphics/graphics.h"
#include "./../util/graphics/resize.h"
#include "./../util/timer/timer.h"

#include "./kernel_gpu_opencl_wrapper.h"

#ifdef TIMING
#include <sys/time.h>
#endif

extern int platform_id_inuse;
extern int device_id_inuse;

void 
kernel_gpu_opencl_wrapper(	fp* image,											
							int Nr,												
							int Nc,												
							long Ne,											
							int niter,											
							fp lambda,											
							long NeROI,											
							int* iN,
							int* iS,
							int* jE,
							int* jW,
							int iter,											
							int mem_size_i,
							int mem_size_j)
{

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
                d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	int blocks_x;
	int mem_size;															
	mem_size = sizeof(fp) * Ne;												

	fp* d_I = (fp*)malloc(mem_size);
	fp* d_iN = (fp*)malloc(mem_size_i);
	fp* d_iS = (fp*)malloc(mem_size_i);
	fp* d_jE = (fp*)malloc(mem_size_j);
	fp* d_jW = (fp*)malloc(mem_size_j);
	fp* d_dN = (fp*)malloc(mem_size);
	fp* d_dS = (fp*)malloc(mem_size);
	fp* d_dW = (fp*)malloc(mem_size);
	fp* d_dE = (fp*)malloc(mem_size);
	fp* d_c = (fp*)malloc(mem_size);
	fp* d_sums = (fp*)malloc(mem_size);
	fp* d_sums2 = (fp*)malloc(mem_size);

	for(long i = 0; i < Ne; i++) {
		d_I[i] = image[i];
	}
	for(int i = 0; i < Nr; i++) {
		d_iN[i] = (fp)iN[i];
		d_iS[i] = (fp)iS[i];
	}
	for(int j = 0; j < Nc; j++) {
		d_jE[j] = (fp)jE[j];
		d_jW[j] = (fp)jW[j];
	}

#ifdef TIMING
    h2d_time = 0;
#endif

	int blocks_work_size;
	blocks_x = Ne/NUMBER_THREADS;
	if (0 != Ne % NUMBER_THREADS) {												
		blocks_x += 1;																	
	}
	blocks_work_size = blocks_x;

	printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", blocks_x, NUMBER_THREADS);

#pragma omp parallel for
	for(long ei = 0; ei < Ne; ei++) {
		d_I[ei] = exp(d_I[ei]/255);
	}

#pragma omp parallel for
	for(long ei = 0; ei < Ne; ei++) {
		d_sums[ei] = d_I[ei];
		d_sums2[ei] = d_I[ei]*d_I[ei];
	}

	int blocks2_x;
	int blocks2_work_size;
	long no;
	int mul;
	int mem_size_single = sizeof(fp) * 1;
	fp total;
	fp total2;
	fp meanROI;
	fp meanROI2;
	fp varROI;
	fp q0sqr;

#pragma omp parallel for
	for(long ei = 0; ei < Ne; ei++) {
		d_sums[ei] = d_I[ei];
		d_sums2[ei] = d_I[ei]*d_I[ei];
	}

	printf("Iterations Progress: hidden");

	for (iter=0; niter > iter; iter++) {										

		fflush(NULL);

		blocks2_work_size = blocks_work_size;							
		no = Ne;														
		mul = 1;														

		while(0 != blocks2_work_size){

			int nf = NUMBER_THREADS-(blocks2_work_size*NUMBER_THREADS-no);				
			int df = 0;

#pragma omp parallel
			{
				fp* d_psum = (fp*)malloc(sizeof(fp) * NUMBER_THREADS);
				fp* d_psum2 = (fp*)malloc(sizeof(fp) * NUMBER_THREADS);

				int tx = omp_get_thread_num();
				int bx = 0;
				int ei = bx*NUMBER_THREADS+tx;

				if(no > ei) {
					d_psum[tx] = d_sums[ei*mul];
					d_psum2[tx] = d_sums2[ei*mul];
				} else {
					d_psum[tx] = 0;
					d_psum2[tx] = 0;
				}

#pragma omp barrier

				if(nf == NUMBER_THREADS) {
					for(int i=2; i<=NUMBER_THREADS; i=2*i) {
						if(0 == (tx+1) % i) {
							d_psum[tx] = d_psum[tx] + d_psum[tx-i/2];
							d_psum2[tx] = d_psum2[tx] + d_psum2[tx-i/2];
						}
#pragma omp barrier
					}

					if(tx==(NUMBER_THREADS-1)) {
						d_sums[bx*mul*NUMBER_THREADS] = d_psum[tx];
						d_sums2[bx*mul*NUMBER_THREADS] = d_psum2[tx];
					}
				} else {
					if(bx != (blocks2_work_size - 1)) {
						for(int i=2; i<=NUMBER_THREADS; i=2*i) {
							if(0 == (tx+1) % i) {
								d_psum[tx] = d_psum[tx] + d_psum[tx-i/2];
								d_psum2[tx] = d_psum2[tx] + d_psum2[tx-i/2];
							}
#pragma omp barrier
						}

						if(tx==(NUMBER_THREADS-1)) {
							d_sums[bx*mul*NUMBER_THREADS] = d_psum[tx];
							d_sums2[bx*mul*NUMBER_THREADS] = d_psum2[tx];
						}
					} else {
						for(int i=2; i<=NUMBER_THREADS; i=2*i) {
							if(i <= nf) {
								df = i;
							}
						}

						for(int i=2; df >= i; i=2*i) {
							if(0 == (tx+1) % i && df > tx) {
								d_psum[tx] = d_psum[tx] + d_psum[tx-i/2];
								d_psum2[tx] = d_psum2[tx] + d_psum2[tx-i/2];
							}
#pragma omp barrier
						}

						if((df-1) == tx) {
							for(int i=(bx*NUMBER_THREADS)+df; i<(bx*NUMBER_THREADS)+nf; i++) {
								d_psum[tx] = d_psum[tx] + d_sums[i];
								d_psum2[tx] = d_psum2[tx] + d_sums2[i];
							}

							d_sums[bx*mul*NUMBER_THREADS] = d_psum[tx];
							d_sums2[bx*mul*NUMBER_THREADS] = d_psum2[tx];
						}
					}
				}

				free(d_psum);
				free(d_psum2);
			}

			no = blocks2_work_size;												
			if(1 == blocks2_work_size) {
				blocks2_work_size = 0;
			} else {
				mul = mul * NUMBER_THREADS;										
				blocks_x = blocks2_work_size/NUMBER_THREADS;			
				if (0 != blocks2_work_size % NUMBER_THREADS) {			
					blocks_x += 1;
				}
				blocks2_work_size = blocks_x;
			}
		}

		total = d_sums[0];
		total2 = d_sums2[0];

		meanROI	= total / (fp)(NeROI);										
		meanROI2 = meanROI * meanROI;										
		varROI = (total2 / (fp)(NeROI)) - meanROI2;							
		q0sqr = varROI / meanROI2;											

#pragma omp parallel for
	for(long ei = 0; ei < Ne; ei++) {
		int row;																
		int col;																

		fp d_Jc;
		fp d_dN_loc, d_dS_loc, d_dW_loc, d_dE_loc;
		fp d_c_loc;
		fp d_G2,d_L,d_num,d_den,d_qsqr;

		row = (ei+1) % Nr - 1;													
		col = (ei+1) / Nr + 1 - 1;												
		if(0 == (ei+1) % Nr) {
			row = Nr - 1;
			col -= 1;
		}

		if(Ne > ei) {
			d_Jc = d_I[ei];

			d_dN_loc = d_I[(int)d_iN[row] + Nr*col] - d_Jc;						
			d_dS_loc = d_I[(int)d_iS[row] + Nr*col] - d_Jc;						
			d_dW_loc = d_I[row + Nr*(int)d_jW[col]] - d_Jc;						
			d_dE_loc = d_I[row + Nr*(int)d_jE[col]] - d_Jc;

			d_G2 = (d_dN_loc*d_dN_loc + d_dS_loc*d_dS_loc + d_dW_loc*d_dW_loc + d_dE_loc*d_dE_loc) / (d_Jc*d_Jc);

			d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

			d_num  = (0.5*d_G2) - ((1.0/16.0)*(d_L*d_L));						
			d_den  = 1 + (0.25*d_L);												
			d_qsqr = d_num/(d_den*d_den);

			d_den = (d_qsqr-q0sqr) / (q0sqr * (1+q0sqr));				
			d_c_loc = 1.0 / (1.0+d_den);

			if (d_c_loc < 0) {
				d_c_loc = 0;
			}
			else if (d_c_loc > 1) {
				d_c_loc = 1;
			}

			d_dN[ei] = d_dN_loc; 
			d_dS[ei] = d_dS_loc; 
			d_dW[ei] = d_dW_loc; 
			d_dE[ei] = d_dE_loc;
			d_c[ei] = d_c_loc;
		}
	}

#pragma omp parallel for
	for(long ei = 0; ei < Ne; ei++) {
		int row;																
		int col;																

		fp d_cN,d_cS,d_cW,d_cE;
		fp d_D;

		row = (ei+1) % Nr - 1;												
		col = (ei+1) / Nr + 1 - 1;											
		if(0 == (ei+1) % Nr) {
			row = Nr - 1;
			col -= 1;
		}

		if(Ne > ei) {
			d_cN = d_c[ei];						
			d_cS = d_c[(int)d_iS[row] + Nr*col];										
			d_cW = d_c[ei];														
			d_cE = d_c[row + Nr * (int)d_jE[col]];

			d_D = d_cN*d_dN[ei] + d_cS*d_dS[ei] + d_cW*d_dW[ei] + d_cE*d_dE[ei];

			d_I[ei] = d_I[ei] + 0.25*lambda*d_D;
		}
	}
	}

	printf("\n");

#pragma omp parallel for
	for(long ei = 0; ei < Ne; ei++) {
		d_I[ei] = log(d_I[ei])*255;
	}

	for(long i = 0; i < Ne; i++) {
		image[i] = d_I[i];
	}

#ifdef TIMING
    d2h_time = 0;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

	free(d_I);
	free(d_c);
	free(d_iN);
	free(d_iS);
	free(d_jE);
	free(d_jW);
	free(d_dN);
	free(d_dS);
	free(d_dE);
	free(d_dW);
	free(d_sums);
	free(d_sums2);

#ifdef TIMING
	printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
